sys_ui_page.client_script:
// dialog_button id="cancel" was clicked, user does not want to delete the task
function onCancel() {
    // below will auto close popup
    GlideDialogWindow.get().destroy();
    return false;
}

// dialog_button id="submit" was clicked, user confirms wanting to delete the task
function onSubmit() {
    return true;
}

sys_ui_page.processing_script:
taskerDelete();

function taskerDelete() {
	var url = '';
	if(sysid){
		// DFCT0010541
		url = 'x_153465_discovert_route_task_instance.do?sys_id=' + sysid;
		var gr_delete_task = new GlideRecord("x_153465_discovert_route_task_instance");
		gr_delete_task.addQuery('sys_id', sysid);
		gr_delete_task.query();
		if (gr_delete_task.next()) {
			// get URL before delete
			if(gr_delete_task.parent){
				url = 'x_153465_discovert_route_task_instance.do?sys_id=' + gr_delete_task.getValue('parent');
			} else {
				url = '/discovertaskerportal';
			}
			// Calls a Server function
			new Task_uiAction().uiAction_DeleteTasks(gr_delete_task);
		}
	} else if(templateTaskSysId){
		// delete template here
		url = 'x_153465_discovert_route_tasks.do?sys_id=' + templateTaskSysId;
		var gr_delete_temp_task = new GlideRecord('x_153465_discovert_route_tasks');
		gr_delete_temp_task.addQuery('sys_id', templateTaskSysId);
		gr_delete_temp_task.query();
		if (gr_delete_temp_task.next()) {
			if(gr_delete_temp_task.parent){
				url = 'x_153465_discovert_route_tasks.do?sys_id=' + gr_delete_temp_task.getValue('parent');
			} else {
				url = '/discovertaskerportal?id=discovertasker_processtemplatelist&table=x_153465_discovert_discover_routing_template';
			}
			new Template_uiAction().uiAction_DeleteTemplateTask(gr_delete_temp_task);
		}		
	} else if(templateSysId){
		// delete template here
		url = 'x_153465_discovert_discover_routing_template.do?sys_id=' + templateSysId;
		var gr_delete_temp = new GlideRecord('x_153465_discovert_discover_routing_template');
		gr_delete_temp.addQuery('sys_id', templateSysId);
		gr_delete_temp.query();
		if (gr_delete_temp.next()) {
			new Template_uiAction().uiAction_DeleteTemplate(gr_delete_temp);
			url = '/discovertaskerportal?id=discovertasker_processtemplatelist&table=x_153465_discovert_discover_routing_template';
		}
	} else if(oooSysId){
		// STRY0131195 - delete Out of Office
		var gr_delete_ooo = new GlideRecordSecure('x_153465_discovert_out_of_office');
		if(gr_delete_ooo.get(oooSysId)){
			new Organization_uiAction().uiAction_deleteOoO(gr_delete_ooo);	
		}
		url='';
	}
	response.sendRedirect(url);
}
